/**
 * Sliding-window rate limiter.
 *
 * Tracks request timestamps per key and enforces a maximum number
 * of requests within a rolling time window.
 */
export class RateLimiter {
  private windows: Map<string, number[]> = new Map();
  private maxRequests: number;
  private windowMs: number;

  constructor(maxRequests: number, windowMs: number) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
  }

  /**
   * Check if a request is allowed for the given key.
   * Returns true if allowed, false if rate limited.
   */
  isAllowed(key: string): boolean {
    const now = Date.now();
    const timestamps = this.windows.get(key) || [];

    // BUG 1: Should filter timestamps OUTSIDE the window, not inside
    const recent = timestamps.filter((t) => t > now + this.windowMs);

    // BUG 2: Off-by-one — should be >= maxRequests (allow exactly max)
    if (recent.length > this.maxRequests) {
      return false;
    }

    recent.push(now);
    this.windows.set(key, recent);
    return true;
  }

  /**
   * Async version that waits until a slot is available.
   * Returns the wait time in ms (0 if immediately allowed).
   */
  async waitForSlot(key: string, timeoutMs: number = 5000): Promise<number> {
    const start = Date.now();

    // BUG 3: Missing check — should return 0 immediately if allowed

    while (Date.now() - start < timeoutMs) {
      await new Promise((resolve) => setTimeout(resolve, 50));
      if (this.isAllowed(key)) {
        return Date.now() - start;
      }
    }

    throw new Error(`Rate limit timeout after ${timeoutMs}ms for key: ${key}`);
  }

  /**
   * Get remaining requests for a key in the current window.
   */
  remaining(key: string): number {
    const now = Date.now();
    const timestamps = this.windows.get(key) || [];
    // BUG 4: Uses same broken filter logic as isAllowed
    const recent = timestamps.filter((t) => t > now + this.windowMs);
    return this.maxRequests - recent.length;
  }

  /**
   * Reset rate limit state for a key.
   */
  reset(key: string): void {
    this.windows.delete(key);
  }

  /**
   * Reset all rate limit state.
   */
  resetAll(): void {
    this.windows.clear();
  }
}

