import { describe, it, expect, beforeEach } from 'bun:test';
import { RateLimiter } from '../src/rate-limiter';

describe('RateLimiter', () => {
  let limiter: RateLimiter;

  beforeEach(() => {
    limiter = new RateLimiter(3, 1000); // 3 requests per 1 second
  });

  it('allows requests up to the limit', () => {
    expect(limiter.isAllowed('user1')).toBe(true);
    expect(limiter.isAllowed('user1')).toBe(true);
    expect(limiter.isAllowed('user1')).toBe(true);
  });

  it('blocks requests over the limit', () => {
    expect(limiter.isAllowed('user1')).toBe(true);
    expect(limiter.isAllowed('user1')).toBe(true);
    expect(limiter.isAllowed('user1')).toBe(true);
    expect(limiter.isAllowed('user1')).toBe(false);
  });

  it('tracks keys independently', () => {
    for (let i = 0; i < 3; i++) limiter.isAllowed('user1');
    expect(limiter.isAllowed('user1')).toBe(false);
    expect(limiter.isAllowed('user2')).toBe(true);
  });

  it('allows requests after the window expires', async () => {
    for (let i = 0; i < 3; i++) limiter.isAllowed('user1');
    expect(limiter.isAllowed('user1')).toBe(false);

    // Wait for window to expire
    await new Promise((r) => setTimeout(r, 1100));
    expect(limiter.isAllowed('user1')).toBe(true);
  });

  it('reports correct remaining count', () => {
    expect(limiter.remaining('user1')).toBe(3);
    limiter.isAllowed('user1');
    expect(limiter.remaining('user1')).toBe(2);
    limiter.isAllowed('user1');
    limiter.isAllowed('user1');
    expect(limiter.remaining('user1')).toBe(0);
  });

  it('reset clears the key state', () => {
    for (let i = 0; i < 3; i++) limiter.isAllowed('user1');
    expect(limiter.isAllowed('user1')).toBe(false);
    limiter.reset('user1');
    expect(limiter.isAllowed('user1')).toBe(true);
  });

  it('waitForSlot returns 0 when immediately allowed', async () => {
    const waited = await limiter.waitForSlot('user1');
    expect(waited).toBe(0);
  });

  it('waitForSlot waits until a slot opens', async () => {
    const fast = new RateLimiter(1, 200); // 1 req per 200ms
    fast.isAllowed('user1');
    const waited = await fast.waitForSlot('user1', 2000);
    expect(waited).toBeGreaterThan(100);
    expect(waited).toBeLessThan(2000);
  });

  it('waitForSlot throws on timeout', async () => {
    for (let i = 0; i < 3; i++) limiter.isAllowed('user1');
    await expect(limiter.waitForSlot('user1', 100)).rejects.toThrow('Rate limit timeout');
  });
});

