type Listener = (...args: unknown[]) => void | Promise<void>;

export class EventEmitter {
  private listeners: Map<string, Set<Listener>> = new Map();
  private onceListeners: WeakSet<Listener> = new WeakSet();
  private maxListeners: number = 10;

  /**
   * Set the maximum number of listeners per event.
   * 0 means unlimited.
   */
  setMaxListeners(n: number): this {
    if (n < 0) throw new RangeError('Max listeners must be non-negative');
    this.maxListeners = n;
    return this;
  }

  getMaxListeners(): number {
    return this.maxListeners;
  }

  /**
   * Register a listener for an event.
   * Supports wildcard '*' to listen to all events.
   */
  on(event: string, listener: Listener): this {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    const set = this.listeners.get(event)!;
    if (this.maxListeners > 0 && set.size >= this.maxListeners) {
      console.warn(
        `MaxListenersExceededWarning: ${set.size + 1} ${event} listeners added. Max is ${this.maxListeners}.`
      );
    }
    set.add(listener);
    return this;
  }

  /**
   * Register a one-time listener.
   */
  once(event: string, listener: Listener): this {
    this.onceListeners.add(listener);
    return this.on(event, listener);
  }

  /**
   * Remove a listener for an event.
   */
  off(event: string, listener: Listener): this {
    const set = this.listeners.get(event);
    if (set) {
      set.delete(listener);
      if (set.size === 0) this.listeners.delete(event);
    }
    return this;
  }

  /**
   * Remove all listeners, optionally for a specific event.
   */
  removeAllListeners(event?: string): this {
    if (event) {
      this.listeners.delete(event);
    } else {
      this.listeners.clear();
    }
    return this;
  }

  /**
   * Emit an event. Calls all listeners synchronously.
   * If a listener is a once-listener, it is removed after invocation.
   * If a listener throws, emission continues and the error is collected.
   * Returns { fired: number, errors: Error[] }.
   */
  emit(event: string, ...args: unknown[]): { fired: number; errors: Error[] } {
    const errors: Error[] = [];
    let fired = 0;

    const invoke = (set: Set<Listener> | undefined) => {
      if (!set) return;
      for (const listener of [...set]) {
        try {
          listener(...args);
          fired++;
          if (this.onceListeners.has(listener)) {
            set.delete(listener);
            this.onceListeners.delete(listener);
          }
        } catch (err) {
          errors.push(err instanceof Error ? err : new Error(String(err)));
          fired++;
          if (this.onceListeners.has(listener)) {
            set.delete(listener);
            this.onceListeners.delete(listener);
          }
        }
      }
    };

    invoke(this.listeners.get(event));
    if (event !== '*') invoke(this.listeners.get('*'));

    return { fired, errors };
  }

  /**
   * Async emit - awaits each listener sequentially.
   */
  async emitAsync(event: string, ...args: unknown[]): Promise<{ fired: number; errors: Error[] }> {
    const errors: Error[] = [];
    let fired = 0;

    const invoke = async (set: Set<Listener> | undefined) => {
      if (!set) return;
      for (const listener of [...set]) {
        try {
          await listener(...args);
          fired++;
          if (this.onceListeners.has(listener)) {
            set.delete(listener);
            this.onceListeners.delete(listener);
          }
        } catch (err) {
          errors.push(err instanceof Error ? err : new Error(String(err)));
          fired++;
          if (this.onceListeners.has(listener)) {
            set.delete(listener);
            this.onceListeners.delete(listener);
          }
        }
      }
    };

    await invoke(this.listeners.get(event));
    if (event !== '*') await invoke(this.listeners.get('*'));

    return { fired, errors };
  }

  /**
   * Return event names that have listeners.
   */
  eventNames(): string[] {
    return [...this.listeners.keys()];
  }

  /**
   * Return the number of listeners for an event.
   */
  listenerCount(event: string): number {
    return this.listeners.get(event)?.size ?? 0;
  }
}

