import { describe, it, expect, beforeEach, afterEach } from 'bun:test';
import { ConfigManager } from '../src/config-manager';

describe('ConfigManager', () => {
  let cm: ConfigManager;

  beforeEach(() => {
    cm = new ConfigManager({
      appName: { type: 'string', required: true, default: 'MyApp' },
      port: { type: 'number', required: true, default: 3000, envVar: 'APP_PORT' },
      debug: { type: 'boolean', default: false, envVar: 'APP_DEBUG' },
      maxRetries: {
        type: 'number',
        default: 3,
        validate: (v) => typeof v === 'number' && v >= 0 && v <= 10,
      },
    });
  });

  afterEach(() => {
    delete process.env.APP_PORT;
    delete process.env.APP_DEBUG;
  });

  it('returns defaults for unset keys', () => {
    expect(cm.get('appName')).toBe('MyApp');
    expect(cm.get('port')).toBe(3000);
    expect(cm.get('debug')).toBe(false);
  });

  it('sets and gets values', () => {
    cm.set('appName', 'TestApp');
    expect(cm.get('appName')).toBe('TestApp');
  });

  it('rejects invalid types silently', () => {
    cm.set('port', 'not-a-number');
    expect(cm.get('port')).toBe(3000); // default
  });

  it('rejects values failing custom validation', () => {
    cm.set('maxRetries', 99);
    expect(cm.get('maxRetries')).toBe(3); // default, 99 rejected
  });

  it('allows null values', () => {
    cm.set('appName', null);
    expect(cm.get('appName')).toBe(null);
  });

  it('env var overrides take priority', () => {
    process.env.APP_PORT = '8080';
    expect(cm.get('port')).toBe(8080);
    cm.set('port', 9090);
    expect(cm.get('port')).toBe(8080); // env still wins
  });

  it('env var boolean coercion', () => {
    process.env.APP_DEBUG = 'true';
    expect(cm.get('debug')).toBe(true);
    process.env.APP_DEBUG = '1';
    expect(cm.get('debug')).toBe(true);
    process.env.APP_DEBUG = 'false';
    expect(cm.get('debug')).toBe(false);
  });

  it('has() checks all sources', () => {
    expect(cm.has('appName')).toBe(true); // default
    expect(cm.has('unknownKey')).toBe(false);
    cm.set('customKey', 'val');
    expect(cm.has('customKey')).toBe(true);
    process.env.APP_PORT = '8080';
    expect(cm.has('port')).toBe(true);
  });

  it('delete removes a key', () => {
    cm.set('appName', 'X');
    cm.delete('appName');
    expect(cm.get('appName')).toBe('MyApp'); // falls back to default
  });

  it('getAll merges defaults, set values, and env vars', () => {
    cm.set('appName', 'Hello');
    process.env.APP_PORT = '4000';
    const all = cm.getAll();
    expect(all.appName).toBe('Hello');
    expect(all.port).toBe(4000);
    expect(all.debug).toBe(false);
  });

  it('validate reports missing required fields', () => {
    const bare = new ConfigManager({ required_key: { type: 'string', required: true } });
    const result = bare.validate();
    expect(result.valid).toBe(false);
    expect(result.errors.length).toBe(1);
  });

  it('onChange listener fires on set', () => {
    const calls: [string, unknown][] = [];
    cm.onChange((k, v) => calls.push([k, v]));
    cm.set('appName', 'Z');
    expect(calls).toEqual([['appName', 'Z']]);
  });

  it('onChange returns unsubscribe function', () => {
    const calls: string[] = [];
    const unsub = cm.onChange((k) => calls.push(k));
    cm.set('appName', 'A');
    unsub();
    cm.set('appName', 'B');
    expect(calls).toEqual(['appName']);
  });

  it('dirty tracking', () => {
    expect(cm.isDirty()).toBe(false);
    cm.set('appName', 'Dirty');
    expect(cm.isDirty()).toBe(true);
    cm.markClean();
    expect(cm.isDirty()).toBe(false);
  });

  it('toJSON and fromJSON round-trip', () => {
    cm.set('appName', 'Serialized');
    cm.set('port', 5000);
    const json = cm.toJSON();
    const cm2 = new ConfigManager({
      appName: { type: 'string' },
      port: { type: 'number' },
    });
    cm2.fromJSON(json);
    expect(cm2.get('appName')).toBe('Serialized');
    expect(cm2.get('port')).toBe(5000);
  });

  it('fromJSON ignores invalid JSON', () => {
    cm.fromJSON('not valid json{{{');
    expect(cm.get('appName')).toBe('MyApp'); // unchanged
  });

  it('setSchema re-validates existing config', () => {
    cm.set('port', 3000);
    cm.setSchema({
      port: { type: 'string', required: true },
    });
    // port was number, schema now says string - should be removed
    expect(cm.get('port')).toBe(null);
  });
});
